query:
-- Jogadores com gold mas overall < 75 (deveriam ser silver ou bronze)
SELECT id, name, overall, cardType FROM players WHERE cardType = 'gold' AND overall < 75 ORDER BY overall DESC LIMIT 10;
-- Jogadores com silver mas overall >= 75 (deveriam ser gold)
SELECT id, name, overall, cardType FROM players WHERE cardType = 'silver' AND overall >= 75 ORDER BY overall DESC LIMIT 10;

